def integerReplacement(self, n: int) -> int:
        steps = 0
        while n > 1:
            if n % 2 == 0:
                n = n // 2
                steps += 1
            else:
                if n == 3:
                    steps += 2
                    break
                if (n + 1) % 4 == 0:
                    n += 1
                    steps += 1
                else:
                    n -= 1
                    steps += 1
        return steps
